INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-06560', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在實驗法，除了自變項可能引起依變項改變外，仍存在其他可能引起依變項改變的因素，研究者希 望藉著不同的實驗設計排除這些可能的威脅因素，以確保存在於自變項與依變項間的因果關係。下 列實驗設計無法排除的威脅因素是那一項？ R  O1   X   O2 R  O1   X   O2 成熟的因素  測驗的因素  選擇的偏差  歷史或外部事件', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06561', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '在實驗研究法裡，提及「內部效度」的問題，下列敘述何者正確？ 內部效度是指實驗的過程必須有效率 內部效度是指實驗的結果是可以推論的 內部效度是指實驗排除其他可能解釋依變項變動因素的信心或程度 內部效度是指實驗的人員必須是受過嚴格訓練的', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06562', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列那一種研究屬於「橫斷面研究」（cross-sectional study）？ 趨勢研究（trend study）  人口普查（census） 代表研究（panel study）  世代研究（cohort study）', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06563', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列那一種研究不屬於非干擾性研究（unobtrusive study）？ 次級資料分析法  焦點團體法  內容分析法  歷史比較分析法', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06564', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關「田野研究」的敘述，何者錯誤？ 田野研究者檢視自然的情境下的社會意義、捕捉多元的觀點，研究者本身就是測量田野資料的 工具 田野研究的「守門人」有權管制研究者能否進入田野從事研究工作，第一次接觸的守門員在田野 的角色會影響或阻礙研究者後續的接觸 田野研究者進入田野後為了要取得田野成員的敬重，最好要能呈現無所不知的專家姿態，不能表 現出天真無知的樣貌 好的田野研究資料的品質在於能夠捕捉社會互動的過程，有品質的資料包含研究者主觀的反應與 經驗', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06565', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關訪問調查的敘述，何者正確？ 訪問調查時，訪員可以根據受訪者的狀況改變問題發問的詞句 當受訪者的回答不夠清楚時，訪員可以繼續追問以取得更多的資訊 受訪者的回答如果用詞太強烈或用詞不恰當，訪員在記錄時可做適度的修正 為了使訪員能清楚及熟悉訪問的內容，訪員應個別訓練', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06566', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列那一項非田野研究訪談的特性？ 結構的  深度的  冗長的  非正式的', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06567', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '使用網路從事社會工作研究的優點是什麼？ 網路加快全球資訊的流通，產生了小眾化的效果 網路提供有限的資料，但以活潑、有趣的形式出現 網路簡單、快速、便宜、隨處可得 關於社會研究很多出色的資料和大部分最重要的資源都在網路上', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06568', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於調查研究法的各種資料蒐集方法之比較，下列敘述何者錯誤？ 郵寄問卷調查比面訪回覆率低  線上調查比面訪回覆率高 電話調查有機會作探查（Probe）  面訪調查有機會作觀察', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06569', 'social-worker', 'social-worker-moex-103-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於調查研究在社會工作領域的主要用途和調查內容，下列何者正確？ 調查內容主要是事實、意見和行為 探索性調查在探討變項與變項之間的關係時使用之 描述性調查係對於事先知道的事情，但不知道其真實狀況時使用之 解釋性調查是重視所要探討事情的全貌時使用之', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:34+00:00", "source_pdf_sha1": "ae82baefbfac", "answer_pdf_sha1": "e85c59b48db8", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
